import React, { useEffect, useState } from 'react';
import axios from 'axios';

const statusColors = {
  'pending': 'secondary',
  'in-progress': 'warning',
  'resolved': 'success'
};

const AdminDashboard = () => {

    const [complaints, setComplaints] = useState({ pending: [], inProgress: [], resolved: [] });
    const [staffList, setStaffList] = useState([]);
    const [search, setSearch] = useState('');
    const [notesEdit, setNotesEdit] = useState({});
    const [statusEdit, setStatusEdit] = useState({});
    const [activeTab, setActiveTab] = useState('pending');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    // ✅ FIXED (moved inside component)
    const [selectedAssign, setSelectedAssign] = useState({});

    useEffect(() => {
        fetchComplaints();
        fetchStaff();
    }, []);

    const fetchComplaints = async () => {
        setLoading(true);
        try {
            const res = await axios.get('http://localhost:5001/api/complaints', {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });
            setComplaints(res.data);
        } catch (err) {
            setError('Failed to fetch complaints');
        }
        setLoading(false);
    };

    const fetchStaff = async () => {
        try {
            const res = await axios.get('http://localhost:5001/api/auth/staff', {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });
            setStaffList(res.data);
        } catch (err) {
            setStaffList([]);
        }
    };

    const handleAssign = async (complaintId, staffId) => {
        try {
            if (!staffId) {
                alert('Please select a staff member to assign.');
                return;
            }

            await axios.put(
                `http://localhost:5001/api/complaints/${complaintId}/assign`,
                { staffId },
                {
                    headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
                }
            );

            fetchComplaints();
        } catch (err) {
            alert('Failed to assign complaint');
        }
    };

    // ✅ NEW HANDLER (ADDED, no change to existing)
    const handleAssignType = (id, value) => {
        setSelectedAssign(prev => ({
            ...prev,
            [id]: value
        }));
    };

    const handleStatusChange = (complaintId, status) => {
        setStatusEdit(prev => ({ ...prev, [complaintId]: status }));
    };

    const handleNotesChange = (complaintId, notes) => {
        setNotesEdit(prev => ({ ...prev, [complaintId]: notes }));
    };

    const handleStatusUpdate = async (complaintId) => {
        await axios.put(
            `http://localhost:5001/api/complaints/${complaintId}/status`,
            {
                status: statusEdit[complaintId],
                resolutionNotes: notesEdit[complaintId]
            },
            {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            }
        );
        fetchComplaints();
    };

    const filteredPending = complaints.pending.filter(c =>
        c.title.toLowerCase().includes(search.toLowerCase()) ||
        c.status.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <div className="container py-4">
            <h2 className="mb-4">Admin Complaint Dashboard</h2>

            <input
                type="text"
                className="form-control mb-3"
                placeholder="Search by title or status"
                value={search}
                onChange={e => setSearch(e.target.value)}
            />

            <table className="table table-bordered">
                <thead>
                    <tr>
                        <th>Title</th>
                        <th>Status</th>
                        <th>Category</th>
                        <th>Assigned To</th>
                        <th>Assign Staff</th>
                        <th>Worker Type</th> {/* ✅ NEW COLUMN */}
                        <th>Status Update</th>
                        <th>Notes</th>
                    </tr>
                </thead>

                <tbody>
                    {filteredPending.map(c => (
                        <tr key={c._id}>
                            <td>{c.title}</td>

                            <td>
                                <span className={`badge bg-${statusColors[c.status]}`}>
                                    {c.status}
                                </span>
                            </td>

                            <td>{c.category}</td>

                            <td>{c.assignedTo?.email || 'Unassigned'}</td>

                            {/* ✅ ORIGINAL STAFF ASSIGN (UNCHANGED) */}
                            <td>
                                <select
                                    className="form-select"
                                    value={c.assignedTo?._id || ''}
                                    onChange={e => handleAssign(c._id, e.target.value)}
                                >
                                    <option value="">Select Staff</option>
                                    {staffList.map(staff => (
                                        <option key={staff._id} value={staff._id}>
                                            {staff.name}
                                        </option>
                                    ))}
                                </select>
                            </td>

                            {/* ✅ NEW DROPDOWN (ADDED ONLY) */}
                            <td>
                                <select
                                    className="form-select"
                                    value={selectedAssign[c._id] || ''}
                                    onChange={(e) => handleAssignType(c._id, e.target.value)}
                                >
                                    <option value="">Select Category</option>
                                    <option value="Mechanic">Mechanic</option>
                                    <option value="Lift Mechanic">Lift Mechanic</option>
                                    <option value="Plumber">Plumber</option>
                                    <option value="Electrician">Electrician</option>
                                </select>
                            </td>

                            {/* ✅ STATUS UPDATE (UNCHANGED) */}
                            <td>
                                <select
                                    className="form-select"
                                    value={statusEdit[c._id] || c.status}
                                    onChange={e => handleStatusChange(c._id, e.target.value)}
                                >
                                    <option value="pending">Pending</option>
                                    <option value="in-progress">In Progress</option>
                                    <option value="resolved">Resolved</option>
                                </select>

                                <button
                                    className="btn btn-sm btn-primary mt-1"
                                    onClick={() => handleStatusUpdate(c._id)}
                                >
                                    Update
                                </button>
                            </td>

                            {/* ✅ NOTES (UNCHANGED) */}
                            <td>
                                <input
                                    type="text"
                                    className="form-control"
                                    value={notesEdit[c._id] || c.resolutionNotes || ''}
                                    onChange={e => handleNotesChange(c._id, e.target.value)}
                                />
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default AdminDashboard;
